from __future__ import annotations

from io import BytesIO
from typing import Any

import pandas as pd


def _read_csv_strict(file_bytes: bytes, **kwargs: Any) -> pd.DataFrame:
    return pd.read_csv(BytesIO(file_bytes), encoding="utf-8", **kwargs)


def load_csv_data(
    uploaded_file,
    chunk_threshold_mb: int = 10,
    chunk_size: int = 50_000,
    max_rows_for_large_file: int = 200_000,
):
    """Load CSV with validation, encoding handling, and chunk loading for large files."""
    metadata = {"chunk_loaded": False, "sampled": False, "error": None}

    filename = getattr(uploaded_file, "name", "")
    if not filename.lower().endswith(".csv"):
        metadata["error"] = "Invalid file type. Please upload a .csv file."
        return pd.DataFrame(), metadata

    raw_bytes = uploaded_file.getvalue()
    file_size_mb = len(raw_bytes) / (1024 * 1024)

    try:
        if file_size_mb > chunk_threshold_mb:
            metadata["chunk_loaded"] = True
            chunks = []
            total_rows = 0

            for chunk in _read_csv_strict(raw_bytes, chunksize=chunk_size):
                chunks.append(chunk)
                total_rows += len(chunk)
                if total_rows >= max_rows_for_large_file:
                    metadata["sampled"] = True
                    break

            if not chunks:
                return pd.DataFrame(), metadata

            df = pd.concat(chunks, ignore_index=True)
            if metadata["sampled"] and len(df) > max_rows_for_large_file:
                df = df.head(max_rows_for_large_file)
            return df, metadata

        return _read_csv_strict(raw_bytes), metadata

    except UnicodeDecodeError:
        metadata["error"] = (
            "Encoding error while reading CSV. Please upload a UTF-8 encoded CSV file."
        )
        return pd.DataFrame(), metadata
    except pd.errors.EmptyDataError:
        metadata["error"] = "The uploaded CSV file has no data."
        return pd.DataFrame(), metadata
    except Exception as exc:  # Defensive fallback for parser and malformed input errors
        metadata["error"] = f"Unable to load CSV: {exc}"
        return pd.DataFrame(), metadata

from __future__ import annotations

import pandas as pd


def get_column_types(df: pd.DataFrame):
    numeric_cols = df.select_dtypes(include=["number"]).columns.tolist()
    categorical_cols = df.select_dtypes(exclude=["number"]).columns.tolist()
    return numeric_cols, categorical_cols


def build_column_profile(df: pd.DataFrame):
    column_info = {}
    for col in df.columns:
        column_info[col] = {
            "dtype": str(df[col].dtype),
            "missing": int(df[col].isna().sum()),
            "unique": int(df[col].nunique(dropna=True)),
        }
    return column_info


def attempt_type_conversion(df: pd.DataFrame, threshold: float = 0.9):
    """
    Attempt safe conversion of mixed/object columns to numeric or datetime
    when conversion confidence is high.
    """
    converted_df = df.copy()
    notes = []

    object_cols = converted_df.select_dtypes(include=["object"]).columns
    for col in object_cols:
        non_null = converted_df[col].dropna()
        if non_null.empty:
            continue

        numeric_try = pd.to_numeric(converted_df[col], errors="coerce")
        numeric_ratio = numeric_try.notna().mean()
        if numeric_ratio >= threshold:
            converted_df[col] = numeric_try
            notes.append(f"{col}: converted to numeric")
            continue

        datetime_try = pd.to_datetime(converted_df[col], errors="coerce")
        datetime_ratio = datetime_try.notna().mean()
        if datetime_ratio >= threshold:
            converted_df[col] = datetime_try
            notes.append(f"{col}: converted to datetime")

    return converted_df, notes


def apply_missing_value_strategy(df: pd.DataFrame, strategy: str):
    cleaned_df = df.copy()

    if strategy == "Drop Rows":
        return cleaned_df.dropna()

    numeric_cols, categorical_cols = get_column_types(cleaned_df)

    if strategy == "Fill with Mean":
        for col in numeric_cols:
            mean_val = cleaned_df[col].mean()
            cleaned_df[col] = cleaned_df[col].fillna(mean_val)
        return cleaned_df

    # Fill Smart (Mean/Unknown)
    for col in numeric_cols:
        mean_val = cleaned_df[col].mean()
        cleaned_df[col] = cleaned_df[col].fillna(mean_val)
    for col in categorical_cols:
        cleaned_df[col] = cleaned_df[col].fillna("Unknown")

    return cleaned_df

