import pandas as pd
import plotly.express as px


def suggest_chart_type(df: pd.DataFrame, x_axis: str) -> str:
    if x_axis in df.columns and pd.api.types.is_datetime64_any_dtype(df[x_axis]):
        return "Line"
    return "Bar"


def build_chart(df: pd.DataFrame, chart_type: str, x_axis: str, y_axis: str):
    if chart_type == "Line":
        return px.line(df, x=x_axis, y=y_axis, markers=True, template="plotly_white")
    if chart_type == "Bar":
        return px.bar(df, x=x_axis, y=y_axis, template="plotly_white")
    if chart_type == "Scatter":
        return px.scatter(df, x=x_axis, y=y_axis, template="plotly_white")
    if chart_type == "Area":
        return px.area(df, x=x_axis, y=y_axis, template="plotly_white")
    if chart_type == "Box":
        return px.box(df, x=x_axis, y=y_axis, points="suspectedoutliers", template="plotly_white")
    if chart_type == "Histogram":
        return px.histogram(df, x=y_axis, template="plotly_white")

    return px.bar(df, x=x_axis, y=y_axis, template="plotly_white")

from __future__ import annotations

import os
from typing import Optional, Tuple

import google.generativeai as genai
import pandas as pd


def generate_ai_insight(df: pd.DataFrame, y_axis: str) -> Tuple[Optional[str], Optional[str]]:
    api_key = os.getenv("GEMINI_API_KEY")
    if not api_key:
        return None, "Missing `GEMINI_API_KEY`. Set it in your environment before generating insights."

    if y_axis not in df.columns:
        return None, f"Column '{y_axis}' not found."

    numeric_series = pd.to_numeric(df[y_axis], errors="coerce").dropna()
    if numeric_series.empty:
        return None, "Selected metric has no numeric values after cleaning."

    stats = numeric_series.describe()
    prompt = f"""
You are a data analyst.

Dataset Summary:
- Metric: {y_axis}
- Mean: {stats["mean"]:.2f}
- Maximum: {stats["max"]:.2f}
- Minimum: {stats["min"]:.2f}
- Standard Deviation: {stats["std"]:.2f}

Provide a concise 2-sentence business insight.
"""

    try:
        genai.configure(api_key=api_key)
        model = genai.GenerativeModel("gemini-1.5-flash")
        response = model.generate_content(prompt)
        text = (response.text or "").strip()
        if not text:
            return None, "Gemini returned an empty response. Please try again."
        return text, None
    except Exception as exc:  # pragma: no cover
        return None, f"Gemini API error: {exc}"

